import urllib.request, re; req=urllib.request.Request('https://html.duckduckgo.com/html/?q=India+Union+Budget+2025-26+infrastructure+subsidy+agriculture+lakh+crore', headers={'User-Agent': 'Mozilla/5.0'}); html=urllib.request.urlopen(req).read().decode('utf-8'); items=re.findall(r'<a class=\"result__snippet[^>]+>(.*?)</a>', html, flags=re.DOTALL); results=repr([re.sub('<[^>]+>', '', i).strip() for i in items][:8]); open('search_results.txt', 'w', encoding='utf-8').write(results)
